Here's a simple C++ function to convert a markdown formatted text to HTML. This function only supports basic markdown syntax like headers, bold, italic, and links. You can extend this function to support more markdown syntax if needed.

```cpp
#include <iostream>
#include <string>
#include <sstream>
#include <regex>

std::string markdownToHtml(const std::string& markdown) {
    std::string result;
    std::istringstream iss(markdown);
    std::string line;

    while (std::getline(iss, line)) {
        line = std::regex_replace(line, std::regex("^### (.*)"), "<h3>$1</h3>");
        line = std::regex_replace(line, std::regex("^## (.*)"), "<h2>$1</h2>");
        line = std::regex_replace(line, std::regex("^# (.*)"), "<h1>$1</h1>");
        line = std::regex_replace(line, std::regex("\\*\\*(.*)\\*\\*"), "<strong>$1</strong>");
        line = std::regex_replace(line, std::regex("\\*(.*)\\*"), "<em>$1</em>");
        line = std::regex_replace(line, std::regex("\\[(.*)\\]\\((.*)\\)"), "<a href=\"$2\">$1</a>");

        result += line + "\n";
    }

    return result;
}

int main() {
    std::string markdown = "# Header 1\n## Header 2\n### Header 3\n**Bold Text**\n*Italic Text*\n[Link Example](https://www.example.com)";
    std::string html = markdownToHtml(markdown);
    std::cout << "HTML:\n" << html << std::endl;

    return 0;
}
```

This code defines a function called `markdownToHtml` that takes a const reference to a `std::string` containing markdown formatted text and returns a `std::string` containing HTML formatted text. The function reads the input string line by line and replaces the markdown syntax with the corresponding HTML tags using regular expressions. Then, it appends the converted line to the result string.

